# Get the animation lines from runs and compare
python3 << 'EOF'
import re

def extract_anims(filename):
    with open(filename, 'rb') as f:
        data = f.read()
    anims = []
    for line in data.split(b'\n'):
        m = re.search(rb'^(.*) seq=(\d+) 32bytes', line)
        if m:
            anims.append((int(m.group(2)), m.group(1)))
    return anims

runs = []
for i in [1, 2, 3]:
    runs.append(extract_anims(f'/tmp/run_{i}.txt'))

# Compare animations across runs
for seq in range(20):
    parts = []
    for r in runs:
        for s, a in r:
            if s == seq:
                parts.append(a)
                break
    # All should be identical
    if len(set(parts)) > 1:
        print(f"DIFF at seq={seq}: {parts}")
    else:
        print(f"seq={seq} OK")
EOF

