# Compare against goldens
for name in noargs bogus count_abc extra_arg count_no_val dashdash version_long version_short help h dash dashdash_help; do
  golden_stdout="/work/work/goldens/${name}.stdout"
  golden_stderr="/work/work/goldens/${name}.stderr"
  golden_exit="/work/work/goldens/${name}.exit"

  # Map args from name
  case "$name" in
    noargs) args="" ;;
    bogus) args="--bogus" ;;
    count_abc) args="-c abc 127.0.0.1" ;;
    extra_arg) args="-c 1 127.0.0.1 extra" ;;
    count_no_val) args="--count" ;;
    dashdash) args="--" ;;
    version_long) args="--version" ;;
    version_short) args="-V" ;;
    help) args="--help" ;;
    h) args="-h" ;;
    dash) args="-" ;;
    dashdash_help) args="-- --help" ;;
  esac

  ./test $args >/tmp/my.out 2>/tmp/my.err
  my_exit=$?

  ok="OK"
  d1=$(diff /tmp/my.out "$golden_stdout" 2>&1 | head -5)
  d2=$(diff /tmp/my.err "$golden_stderr" 2>&1 | head -5)
  if [ -n "$d1" ]; then ok="STDOUT_DIFF"; fi
  if [ -n "$d2" ]; then ok="${ok}_STDERR_DIFF"; fi
  if [ "$my_exit" != "$(cat $golden_exit)" ]; then ok="${ok}_EXIT_DIFF($my_exit vs $(cat $golden_exit))"; fi

  printf "%-20s %s\n" "$name" "$ok"
  if [ -n "$d1" ]; then echo "  STDOUT: $d1"; fi
  if [ -n "$d2" ]; then echo "  STDERR: $d2"; fi
done

